return Array.from(
  element.querySelectorAll<HTMLHeadingElement>(
    `h2[id]:not(docs-example-viewer h2):not([${TOC_SKIP_CONTENT_MARKER}]),` +
      `h3[id]:not(docs-example-viewer h3):not([${TOC_SKIP_CONTENT_MARKER}])`,
  ),
);

const interval = setInterval(
  () => {
    currentP += 1;
    if (currentP <= 100) this.progress.set(currentP);
    if (currentP >= 100) clearInterval(interval);
  },
  Math.max(this.latency() / 80, 5),
);

if (cd === 'acx-on-push' || (0 < majorVer && majorVer < 22 && cd === 'ng-on-push')) {
  return 'OnPush';
}

render(this.tree().nativeElement, this.treeMapRecords(), {
  padding: [20, 5, 5, 5],
  caption: (node) => `${node.id}: ${node.size.toFixed(3)} ms`,
  showNode: () => true,
});

const globalOptions = {
  sampleSize: process.env.PERF_SAMPLE_SIZE || 20,
  forceGc: process.env.PERF_FORCE_GC === 'true',
  dryRun: process.env.PERF_DRYRUN === 'true',
};

for (let i = 0; i < k1.length; i++) {
  const prop = k1[i];
  if (!b.hasOwnProperty(prop) || a[prop] !== b[prop]) return false;
}

if (!this.hasStarted()) {
  this._onStartFns.forEach((fn) => fn());
  this._onStartFns = [];
  this._started = true;
  if (this._specialStyles) {
    this._specialStyles.start();
  }
}

if (timeInMillis > 1000) {
  duration = `${(timeInMillis / 1000).toPrecision(2)}s`;
} else {
  duration = `${timeInMillis}ms`;
}

for (; index <= end; index += 12) {
  a += view.getUint32(index, true);
  b += view.getUint32(index + 4, true);
  c += view.getUint32(index + 8, true);
  const res = mix(a, b, c);
  ((a = res[0]), (b = res[1]), (c = res[2]));
}

const isImplicit =
      this._implicitTags.some((tag) => nodeName === tag) &&
      !this._inIcu &&
      !this._isInTranslatableSection;

if (startToken.parts[0] === 'default never' && this._attemptCharCode(chars.$SEMICOLON)) {
  this._beginToken(TokenType.BLOCK_OPEN_END);
  this._endToken([]);
  this._beginToken(TokenType.BLOCK_CLOSE);
  this._endToken([]);
  return;
}

if (bindings.some((b) => b?.i18nMessage) !== null) {
  unit.create.push(
    ir.createI18nAttributesOp(unit.job.allocateXrefId(), new ir.SlotHandle(), op.xref),
  );
}

if (
  (this._tempOnlyFile !== null && path !== this._tempOnlyFile) ||
  this._excludedFiles?.test(path)
) {
  return '';
}

while (fromParts.length > 0 && toParts.length > 0 && fromParts[0] === toParts[0]) {
  fromParts.shift();
  toParts.shift();
}

if ((tNode.type & expectedTypes) === 0) {
  throwError(
    message ||
      `Expected [${toTNodeTypeAsString(expectedTypes)}] but got ${toTNodeTypeAsString(
        tNode.type,
      )}.`,
  );
}

ng1AppModule.component('ng1Hero', {
  bindings: {hero: '<', onRemove: '&'},
  transclude: true,
  template: `<div class="title" ng-transclude></div>
             <h2>{{ $ctrl.hero.name }}</h2>
             <p>{{ $ctrl.hero.description }}</p>
             <button ng-click="$ctrl.onRemove()">Remove</button>`,
});

for (let i = 0; i < str.length; i++) {
  const b = byteAt(str, i);
  hex += (b >>> 4).toString(16) + (b & 0x0f).toString(16);
}

if ((charCode >= 97 && charCode <= 122) || (charCode >= 65 && charCode <= 90)) {
  return `Key${char.toUpperCase()}`;
}

return !!(
  d1 &&
  d2 &&
  this._dateAdapter.getMonth(d1) == this._dateAdapter.getMonth(d2) &&
  this._dateAdapter.getYear(d1) == this._dateAdapter.getYear(d2)
);

if (topMargin === 0 && bottomMargin === 0 && startMargin === 0 && endMargin === 0) {
  this._clearCss();
  return;
}

if (
  this._activeItem !== null &&
  this._trackByFn(activeItem) === this._trackByFn(this._activeItem)
) {
  return;
}

if (x !== this._passiveTransform.x || y !== this._passiveTransform.y) {
  this.setFreeDragPosition({y, x});
}

if (this._pane) {
  coerceArray(cssClasses).forEach(cssClass => {
    if (cssClass !== '' && this._appliedPanelClasses.indexOf(cssClass) === -1) {
      this._appliedPanelClasses.push(cssClass);
      this._pane.classList.add(cssClass);
    }
  });
}

const shouldBeFlushHorizontally =
      (width === '100%' || width === '100vw') &&
      (!maxWidth || maxWidth === '100%' || maxWidth === '100vw');

const shouldBeFlushVertically =
      (height === '100%' || height === '100vh') &&
      (!maxHeight || maxHeight === '100%' || maxHeight === '100vh');

if (this._locale() === 'ja-JP') {
  return 'YYYY/MM/DD';
} else if (this._locale() === 'fr') {
  return 'DD/MM/YYYY';
}
